import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { useRouter } from 'expo-router';
import type { ComponentProps } from 'react';
import { useState } from 'react';
import { Pressable, StyleSheet, TextInput, View } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { DibsLogo } from '@/components/dibs-logo';
import { ThemedText } from '@/components/themed-text';
import { ThemedView } from '@/components/themed-view';
import { Colors, FontFamilies } from '@/constants/theme';
import { useAuth } from '@/hooks/use-auth';
import { useColorScheme } from '@/hooks/use-color-scheme';

export default function SignupScreen() {
  const router = useRouter();
  const { signUp } = useAuth();
  const colorScheme = useColorScheme() ?? 'light';
  const theme = Colors[colorScheme];

  const [fullName, setFullName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [agreedToTerms, setAgreedToTerms] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const inputBg = theme.inputBg;
  const placeholderColor = colorScheme === 'dark' ? 'rgba(255,255,255,0.2)' : 'rgba(15,26,43,0.4)';

  const handleCreateAccount = async () => {
    if (password !== confirmPassword) {
      console.error("Passwords do not match");
      return;
    }
    const { error } = await signUp(email, password);
    if (!error) {
      router.replace('/(auth)/face-enroll');
    } else {
      console.error(error.message);
    }
  };

  return (
    <ThemedView style={styles.screen}>
      <SafeAreaView style={styles.safeArea} edges={['top', 'bottom']}>
        <View style={styles.content}>
          <View style={styles.logoContainer}>
            <DibsLogo width={200} height={77} />
          </View>

          <View style={styles.form}>
            <ThemedText type="title" style={[styles.headerTitle, { color: theme.text }]}>
              Create an account
            </ThemedText>
            <ThemedText style={[styles.subTitle, { color: theme.mutedText }]}>
              Use your email to get started
            </ThemedText>
            <Field
              label="Full Name"
              placeholder="e.g. Jenny Wilson"
              value={fullName}
              onChangeText={setFullName}
              theme={theme}
              inputBg={inputBg}
              placeholderColor={placeholderColor}
            />
            <Field
              label="Email address"
              placeholder="e.g. wilson09@gmail.com"
              value={email}
              onChangeText={setEmail}
              theme={theme}
              inputBg={inputBg}
              placeholderColor={placeholderColor}
              autoCapitalize="none"
              keyboardType="email-address"
              textContentType="emailAddress"
            />
            <PasswordField
              label="Password"
              placeholder="•••••••••••••"
              value={password}
              onChangeText={setPassword}
              theme={theme}
              inputBg={inputBg}
              placeholderColor={placeholderColor}
              secureTextEntry={!showPassword}
              onToggleVisibility={() => setShowPassword((v) => !v)}
              textContentType="newPassword"
            />
            <PasswordField
              label="Confirm Password"
              placeholder="•••••••••••••"
              value={confirmPassword}
              onChangeText={setConfirmPassword}
              theme={theme}
              inputBg={inputBg}
              placeholderColor={placeholderColor}
              secureTextEntry={!showConfirmPassword}
              onToggleVisibility={() => setShowConfirmPassword((v) => !v)}
              textContentType="newPassword"
            />

            <Pressable
              onPress={() => setAgreedToTerms(!agreedToTerms)}
              style={styles.checkboxRow}>
              <View
                style={[
                  styles.checkbox,
                  {
                    backgroundColor: agreedToTerms ? theme.accent : 'transparent',
                    borderColor: colorScheme === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(15,26,43,0.15)',
                  },
                ]}>
                {agreedToTerms && <ThemedText style={styles.checkmark}>✓</ThemedText>}
              </View>
              <ThemedText style={[styles.checkboxLabel, { color: theme.mutedText }]}>
                I've read and agree to the terms of privacy policy
              </ThemedText>
            </Pressable>

            <Pressable
              onPress={handleCreateAccount}
              style={({ pressed }) => [
                styles.primaryButton,
                { backgroundColor: theme.primary, opacity: pressed ? 0.92 : 1 },
              ]}>
              <ThemedText style={styles.primaryButtonText}>Create Account</ThemedText>
            </Pressable>
          </View>

          <Pressable
            onPress={() => router.replace('/(auth)/login')}
            style={({ pressed }) => [styles.footerLink, { opacity: pressed ? 0.8 : 1 }]}>
            <ThemedText style={[styles.footerLinkText, { color: theme.mutedText }]}>
              Already have an account? Sign in
            </ThemedText>
          </Pressable>
        </View>
      </SafeAreaView>
    </ThemedView>
  );
}

function Field({
  label,
  placeholder,
  theme,
  inputBg,
  placeholderColor,
  ...props
}: {
  label: string;
  placeholder?: string;
  theme: typeof Colors.light;
  inputBg: string;
  placeholderColor: string;
} & ComponentProps<typeof TextInput>) {
  return (
    <View style={styles.fieldWrap}>
      <ThemedText style={[styles.fieldLabel, { color: theme.text }]}>{label}</ThemedText>
      <TextInput
        placeholder={placeholder ?? label}
        placeholderTextColor={placeholderColor}
        style={[
          styles.input,
          {
            backgroundColor: inputBg,
            borderColor: theme.inputBorder,
            color: theme.text,
          },
        ]}
        {...props}
      />
    </View>
  );
}

function PasswordField({
  label,
  placeholder,
  theme,
  inputBg,
  placeholderColor,
  secureTextEntry,
  onToggleVisibility,
  ...props
}: {
  label: string;
  placeholder?: string;
  theme: typeof Colors.light;
  inputBg: string;
  placeholderColor: string;
  secureTextEntry: boolean;
  onToggleVisibility: () => void;
} & ComponentProps<typeof TextInput>) {
  return (
    <View style={styles.fieldWrap}>
      <ThemedText style={[styles.fieldLabel, { color: theme.text }]}>{label}</ThemedText>
      <View style={styles.passwordInputWrap}>
        <TextInput
          placeholder={placeholder ?? label}
          placeholderTextColor={placeholderColor}
          secureTextEntry={secureTextEntry}
          style={[
            styles.input,
            styles.inputWithRightIcon,
            {
              backgroundColor: inputBg,
              borderColor: theme.inputBorder,
              color: theme.text,
            },
          ]}
          {...props}
        />
        <Pressable
          onPress={onToggleVisibility}
          style={styles.eyeButton}
          hitSlop={12}
          accessibilityLabel={secureTextEntry ? 'Show password' : 'Hide password'}>
          <MaterialIcons
            name={secureTextEntry ? 'visibility-off' : 'visibility'}
            size={22}
            color={theme.mutedText}
          />
        </Pressable>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  screen: { flex: 1 },
  safeArea: { flex: 1, paddingHorizontal: 16 },
  content: { flex: 1, paddingTop: 24, justifyContent: 'space-between' },
  logoContainer: { alignItems: 'center', marginBottom: 32 },
  headerTitle: { fontSize: 24, lineHeight: 30, letterSpacing: -1, marginBottom: 4 },
  subTitle: { fontSize: 14, lineHeight: 22, opacity: 0.9, marginBottom: 24 },
  form: { gap: 12 },
  fieldWrap: { marginBottom: 4 },
  fieldLabel: { fontSize: 14, lineHeight: 22, marginBottom: 6 },
  input: {
    height: 54,
    borderRadius: 8,
    borderWidth: 1,
    paddingHorizontal: 20,
    fontSize: 14,
    fontFamily: FontFamilies.regular,
  },
  passwordInputWrap: { position: 'relative', justifyContent: 'center' },
  inputWithRightIcon: { paddingRight: 48 },
  eyeButton: {
    position: 'absolute',
    right: 14,
    padding: 4,
    justifyContent: 'center',
    alignItems: 'center',
  },
  checkboxRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 10,
    marginTop: 8,
  },
  checkbox: {
    width: 22,
    height: 22,
    borderRadius: 4,
    borderWidth: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  checkmark: { color: '#FFF', fontSize: 12, fontFamily: FontFamilies.semiBold },
  checkboxLabel: { flex: 1, fontSize: 14, lineHeight: 22 },
  primaryButton: {
    height: 46,
    borderRadius: 10,
    alignItems: 'center',
    justifyContent: 'center',
    marginTop: 12,
  },
  primaryButtonText: { color: '#FFFFFF', fontSize: 14, fontFamily: FontFamilies.semiBold },
  footerLink: { paddingVertical: 16, alignItems: 'center' },
  footerLinkText: { fontSize: 14, fontFamily: FontFamilies.medium },
});

import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { LinearGradient } from 'expo-linear-gradient';
import { Image } from 'expo-image';
import { useRouter } from 'expo-router';
import { useState } from 'react';
import { ScrollView, StyleSheet, View } from 'react-native';
import { Pressable } from 'react-native';
import { SafeAreaView } from 'react-native-safe-area-context';

import { DibsLogo } from '@/components/dibs-logo';
import { SideMenu } from '@/components/side-menu';
import { ThemedText } from '@/components/themed-text';
import { ThemedView } from '@/components/themed-view';
import { Colors, FontFamilies } from '@/constants/theme';
import { useColorScheme } from '@/hooks/use-color-scheme';

type ActivityItem = {
  id: string;
  title: string;
  subtitle: string;
  time: string;
  type: 'success' | 'danger' | 'blue';
};

const ACTIVITY: ActivityItem[] = [
  { id: '1', title: 'Biometric Verified', subtitle: 'Gallery Access', time: '2m ago', type: 'success' },
  { id: '2', title: 'Screenshot Blocked', subtitle: 'Unauthorized Attempt', time: '1h ago', type: 'danger' },
  { id: '3', title: 'Vault Encryption Cycle', subtitle: 'Automated Routine', time: '3h ago', type: 'blue' },
];

export default function HomeScreen() {
  const colorScheme = useColorScheme() ?? 'light';
  const theme = Colors[colorScheme];
  const router = useRouter();
  const [sideMenuOpen, setSideMenuOpen] = useState(false);

  return (
    <ThemedView style={styles.screen}>
      <SafeAreaView edges={['top']} style={styles.safeArea}>
        <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
          {/* Top bar: sidebar (g59oc) | centered logo (BM6JB) | notification (pKd4o) */}
          <View style={styles.topBar}>
            <Pressable
              onPress={() => setSideMenuOpen(true)}
              style={({ pressed }) => [styles.topBarButton, pressed && styles.topBarButtonPressed]}
              hitSlop={12}
              accessibilityLabel="Open menu"
            >
              <MaterialIcons name="menu" size={28} color={theme.text} />
            </Pressable>
            <View style={styles.logoRow}>
              <DibsLogo width={110} height={42} />
            </View>
            <Pressable
              onPress={() => {}}
              style={({ pressed }) => [styles.topBarButton, styles.topBarButtonRight, pressed && styles.topBarButtonPressed]}
              hitSlop={12}
              accessibilityLabel="Notifications"
            >
              <MaterialIcons name="notifications" size={26} color={theme.text} />
              <View style={[styles.notificationBadge, { backgroundColor: theme.primary }]} />
            </Pressable>
          </View>
          <View style={styles.header}>
            <View style={styles.avatarWrap}>
              <Image
                source={require('../../assets/images/face.png')}
                style={styles.avatar}
              />
            </View>
            <View style={styles.userInfo}>
              <ThemedText style={[styles.welcomeLabel, { color: theme.mutedText }]}>Welcome back,</ThemedText>
              <ThemedText style={[styles.userName, { color: theme.text }]}>Roger Smith</ThemedText>
            </View>
            <View
              style={[
                styles.protectedPill,
                {
                  backgroundColor: colorScheme === 'dark' ? 'rgba(34, 198, 217, 0.1)' : 'rgba(34, 198, 217, 0.08)',
                  borderColor: colorScheme === 'dark' ? 'rgba(34, 198, 217, 0.2)' : 'rgba(34, 198, 217, 0.2)',
                },
              ]}>
              <MaterialIcons name="verified-user" size={12} color={theme.accent} />
              <ThemedText style={[styles.protectedText, { color: theme.accent }]}>Protected</ThemedText>
            </View>
          </View>

          <View style={[styles.divider, { backgroundColor: theme.border }]} />

          <View style={styles.statsRow}>
            <Pressable
              style={({ pressed }) => [
                styles.statCard,
                {
                  backgroundColor: theme.cardTint,
                  borderColor: theme.cardTintBorder,
                  opacity: pressed ? 0.9 : 1,
                },
              ]}>
              <LinearGradient
                colors={theme.primary === '#E21D20' ? ['#FF3B3E', '#E21D20'] : theme.dangerGradient}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 1 }}
                style={styles.statIcon}>
                <MaterialIcons name="image" size={18} color="#FFF" />
              </LinearGradient>
              <ThemedText style={[styles.statValue, { color: theme.text }]}>1,240</ThemedText>
              <ThemedText style={[styles.statLabel, { color: theme.mutedText }]}>protected images</ThemedText>
            </Pressable>
            <Pressable
              style={({ pressed }) => [
                styles.statCard,
                {
                  backgroundColor: theme.cardTint,
                  borderColor: theme.cardTintBorder,
                  opacity: pressed ? 0.9 : 1,
                },
              ]}>
              <LinearGradient
                colors={theme.blueGradient}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 1 }}
                style={styles.statIcon}>
                <MaterialIcons name="videocam" size={18} color="#FFF" />
              </LinearGradient>
              <ThemedText style={[styles.statValue, { color: theme.text }]}>315</ThemedText>
              <ThemedText style={[styles.statLabel, { color: theme.mutedText }]}>protected videos</ThemedText>
            </Pressable>
          </View>

          <View style={styles.sectionHeader}>
            <ThemedText style={[styles.sectionTitle, { color: theme.text }]}>Recent Activity</ThemedText>
            <Pressable onPress={() => router.push('/(tabs)/logs')} hitSlop={8}>
              <ThemedText style={[styles.viewLogText, { color: theme.accent }]}>View Log</ThemedText>
            </Pressable>
          </View>

          <View style={[styles.activityList, { backgroundColor: theme.cardTint, borderWidth: 1, borderColor: theme.cardTintBorder }]}>
            {ACTIVITY.map((item, index) => (
                <View
                  key={item.id}
                  style={[
                    styles.activityRow,
                    index > 0 && { borderTopWidth: 1, borderTopColor: theme.cardTintBorder },
                  ]}>
                  <View style={[styles.activityIcon, { backgroundColor: item.type === 'success' ? 'rgba(57, 198, 149, 0.2)' : item.type === 'danger' ? 'rgba(239, 68, 68, 0.2)' : 'rgba(96, 165, 250, 0.2)' }]}>
                    {item.type === 'success' ? (
                      <MaterialIcons name="verified-user" size={18} color={theme.success} />
                    ) : item.type === 'danger' ? (
                      <MaterialIcons name="block" size={18} color={theme.danger} />
                    ) : (
                      <MaterialIcons name="sync" size={18} color={theme.blueGradient[0]} />
                    )}
                  </View>
                  <View style={styles.activityBody}>
                    <ThemedText style={[styles.activityTitle, { color: theme.text }]}>{item.title}</ThemedText>
                    <View style={styles.activityMeta}>
                      <ThemedText style={[styles.activitySubtitle, { color: theme.mutedText }]}>{item.subtitle}</ThemedText>
                      <View style={[styles.activityDot, { backgroundColor: theme.mutedText }]} />
                      <ThemedText style={[styles.activityTime, { color: theme.mutedText }]}>{item.time}</ThemedText>
                    </View>
                  </View>
                  <MaterialIcons name="chevron-right" size={20} color={theme.mutedText} style={{ opacity: 0.5 }} />
                </View>
            ))}
          </View>
        </ScrollView>
      </SafeAreaView>
      <SideMenu visible={sideMenuOpen} onClose={() => setSideMenuOpen(false)} />
    </ThemedView>
  );
}

const styles = StyleSheet.create({
  screen: { flex: 1 },
  safeArea: { flex: 1 },
  content: { paddingHorizontal: 16, paddingBottom: 120, paddingTop: 8 },
  topBar: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingVertical: 20,
    paddingHorizontal: 0,
  },
  topBarButton: {
    width: 48,
    height: 48,
    alignItems: 'center',
    justifyContent: 'center',
  },
  topBarButtonRight: { position: 'relative' },
  topBarButtonPressed: { opacity: 0.7 },
  notificationBadge: {
    position: 'absolute',
    top: 8,
    right: 8,
    width: 8,
    height: 8,
    borderRadius: 4,
  },
  logoRow: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 14,
    paddingVertical: 16,
  },
  avatarWrap: {
    width: 56,
    height: 56,
    borderRadius: 28,
    overflow: 'hidden',
    borderWidth: 2,
    borderColor: 'transparent',
  },
  avatar: { width: '100%', height: '100%', borderRadius: 28 },
  userInfo: { flex: 1, minWidth: 0 },
  welcomeLabel: { fontSize: 13, lineHeight: 20 },
  userName: { fontSize: 20, fontFamily: FontFamilies.medium, letterSpacing: -1, lineHeight: 30 },
  protectedPill: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 6,
    paddingHorizontal: 13,
    paddingVertical: 7,
    borderRadius: 40,
    borderWidth: 1,
  },
  protectedText: { fontSize: 11, fontFamily: FontFamilies.medium },
  divider: { height: 1, marginVertical: 10, opacity: 0.05 },
  statsRow: { flexDirection: 'row', gap: 19, marginBottom: 16 },
  statCard: {
    flex: 1,
    borderRadius: 18,
    borderWidth: 1,
    padding: 16,
    minHeight: 128,
  },
  statIcon: {
    width: 40,
    height: 40,
    borderRadius: 10,
    alignItems: 'center',
    justifyContent: 'center',
    marginBottom: 8,
  },
  statValue: { fontSize: 24, fontFamily: FontFamilies.semiBold, lineHeight: 30 },
  statLabel: { fontSize: 10, letterSpacing: 1, lineHeight: 30, textTransform: 'lowercase' },
  sectionHeader: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    marginBottom: 12,
  },
  sectionTitle: { fontSize: 20, fontFamily: FontFamilies.semiBold, lineHeight: 30 },
  viewLogText: { fontSize: 12, fontFamily: FontFamilies.medium },
  activityList: { borderRadius: 18, overflow: 'hidden' },
  activityRow: {
    flexDirection: 'row',
    alignItems: 'center',
    paddingVertical: 16,
    paddingHorizontal: 16,
    gap: 12,
  },
  activityIcon: {
    width: 40,
    height: 40,
    borderRadius: 20,
    alignItems: 'center',
    justifyContent: 'center',
  },
  activityBody: { flex: 1, minWidth: 0 },
  activityTitle: { fontSize: 14, fontFamily: FontFamilies.regular, lineHeight: 30 },
  activityMeta: { flexDirection: 'row', alignItems: 'center', gap: 6 },
  activitySubtitle: { fontSize: 12 },
  activityDot: { width: 3, height: 3, borderRadius: 1.5 },
  activityTime: { fontSize: 12 },
});

import MaterialIcons from '@expo/vector-icons/MaterialIcons';
import { useRouter } from 'expo-router';
import { useState } from 'react';
import { Alert, Pressable, ScrollView, StyleSheet, TextInput, View } from 'react-native';
import { SafeAreaView, useSafeAreaInsets } from 'react-native-safe-area-context';

import { ThemedText } from '@/components/themed-text';
import { ThemedView } from '@/components/themed-view';
import { Colors, FontFamilies } from '@/constants/theme';
import { useColorScheme } from '@/hooks/use-color-scheme';

type LogItem = {
  id: string;
  name: string;
  details: string;
  device: string;
  status: 'verified' | 'blocked';
  type: 'success' | 'danger';
};

const LOG_ITEMS: LogItem[] = [
  {
    id: '1',
    name: 'John Doe',
    details: 'Biometric Match • ID: 8821',
    device: 'iPhone 13 Pro',
    status: 'verified',
    type: 'success',
  },
  {
    id: '2',
    name: 'Unknown User',
    details: 'Face Mismatch • ID: N/A',
    device: 'Samsung S21',
    status: 'blocked',
    type: 'danger',
  },
  {
    id: '3',
    name: 'Sarah Miller',
    details: 'Fingerprint • ID: 4102',
    device: 'MacBook Pro',
    status: 'verified',
    type: 'success',
  },
];

// Floating download FAB sits above tab bar — Pencil VxSUD (teal 46px) + RrBHK (download icon)
const DOWNLOAD_FAB_SIZE = 46;
const TAB_BAR_HEIGHT = 76;

export default function LogsScreen() {
  const colorScheme = useColorScheme() ?? 'light';
  const theme = Colors[colorScheme];
  const insets = useSafeAreaInsets();
  const [search, setSearch] = useState('');

  const exportLogs = () => {
    // TODO: wire to real export (share file, save to storage)
    Alert.alert('Export Logs', 'Log export will be available here.');
  };

  return (
    <ThemedView style={styles.screen}>
      <SafeAreaView edges={['top']} style={styles.safeArea}>
        {/* Header — Pencil: Ma4qu (icon), 667xr (title), pN3cI + tMduy (filter) */}
        <View style={styles.header}>
          <View style={[styles.headerIcon, { backgroundColor: theme.cardTint }]}>
            <MaterialIcons name="access-time" size={24} color={theme.accent} />
          </View>
          <ThemedText style={[styles.headerTitle, { color: theme.text }]}>Audit & Access Logs</ThemedText>
          <Pressable
            style={[styles.filterButton, { backgroundColor: theme.cardTint, borderColor: theme.cardTintBorder }]}
            onPress={() => {}}
            hitSlop={8}
          >
            <MaterialIcons name="filter-list" size={18} color={theme.text} />
          </Pressable>
        </View>

        {/* Search — Pencil MeZcF (343x36, radius 6) */}
        <View style={[styles.searchWrap, { backgroundColor: theme.inputBg, borderColor: theme.inputBorder }]}>
          <MaterialIcons name="search" size={18} color={theme.mutedText} />
          <TextInput
            placeholder="Search logs..."
            placeholderTextColor={theme.mutedText}
            value={search}
            onChangeText={setSearch}
            style={[styles.searchInput, { color: theme.text }]}
          />
        </View>

        {/* Section — TODAY + Events pill */}
        <View style={styles.sectionRow}>
          <ThemedText style={[styles.sectionLabel, { color: theme.text }]}>TODAY</ThemedText>
          <View style={[styles.eventPill, { backgroundColor: theme.cardTint, borderColor: theme.cardTintBorder }]}>
            <ThemedText style={[styles.eventPillText, { color: theme.accent }]}>{LOG_ITEMS.length} Events</ThemedText>
          </View>
        </View>

        <View style={[styles.divider, { backgroundColor: theme.border }]} />

        <ScrollView contentContainerStyle={styles.list} showsVerticalScrollIndicator={false}>
          {LOG_ITEMS.map((item) => (
            <View
              key={item.id}
              style={[styles.logCard, { backgroundColor: theme.cardTint, borderColor: theme.cardTintBorder }]}>
              <View style={styles.logTopRow}>
                <View
                  style={[
                    styles.logIcon,
                    { backgroundColor: item.type === 'success' ? 'rgba(57, 198, 149, 0.2)' : 'rgba(239, 68, 68, 0.2)' },
                  ]}>
                  <MaterialIcons
                    name={item.type === 'success' ? 'check-circle' : 'block'}
                    size={20}
                    color={item.type === 'success' ? theme.success : theme.danger}
                  />
                </View>
                <ThemedText style={[styles.logName, { color: theme.text }]}>{item.name}</ThemedText>
                <View
                  style={[
                    styles.statusButton,
                    item.status === 'verified'
                      ? { backgroundColor: theme.surface, borderColor: theme.border }
                      : { backgroundColor: theme.danger },
                  ]}>
                  <ThemedText
                    style={[
                      styles.statusButtonText,
                      { color: item.status === 'verified' ? theme.text : '#FFF' },
                    ]}>
                    {item.status === 'verified' ? 'Verified' : 'Blocked'}
                  </ThemedText>
                </View>
              </View>
              <ThemedText style={[styles.logDetails, { color: theme.mutedText }]}>{item.details}</ThemedText>
              <View style={[styles.deviceTag, { backgroundColor: colorScheme === 'dark' ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.06)' }]}>
                <MaterialIcons name="smartphone" size={14} color={theme.mutedText} />
