                  styles.listItem,
                  {
                    borderColor: theme.border,
                    backgroundColor: colorScheme === 'dark' ? 'rgba(12, 18, 32, 0.6)' : 'rgba(255, 255, 255, 0.92)',
                    opacity: pressed ? 0.84 : 1,
