import { useColorScheme } from '@/hooks/use-color-scheme';

const MENU_WIDTH = 288;
const ANIM_DURATION = 300;
const PANEL_TOP_MARGIN = 24;

type MenuItem = {
  id: string;
  label: string;
  icon: keyof typeof MaterialIcons.glyphMap;
  iconColor?: string;
  iconGradient?: readonly [string, string];
  onPress?: () => void;
};

export type SideMenuProps = {
  visible: boolean;
  onClose: () => void;
};

export function SideMenu({ visible, onClose }: SideMenuProps) {
  const colorScheme = useColorScheme() ?? 'light';
  const theme = Colors[colorScheme];
  const isDark = colorScheme === 'dark';
  const router = useRouter();
  const portalRef = useOverlayPortal();

  const panelX = useRef(new RNAnimated.Value(-MENU_WIDTH)).current;
  const backdropOpacity = useRef(new RNAnimated.Value(0)).current;

  useEffect(() => {
    if (visible) {
      panelX.setValue(-MENU_WIDTH);
      backdropOpacity.setValue(0);
      RNAnimated.parallel([
        RNAnimated.timing(panelX, {
          toValue: 0,
          duration: ANIM_DURATION,
          easing: Easing.out(Easing.cubic),
          useNativeDriver: true,
        }),
        RNAnimated.timing(backdropOpacity, {
          toValue: 1,
          duration: ANIM_DURATION,
          easing: Easing.out(Easing.cubic),
          useNativeDriver: true,
        }),
      ]).start();
    } else {
      panelX.setValue(-MENU_WIDTH);
      backdropOpacity.setValue(0);
    }
  }, [visible]);

  const closeMenu = () => {
    RNAnimated.parallel([
      RNAnimated.timing(panelX, {
        toValue: -MENU_WIDTH,
        duration: ANIM_DURATION,
        easing: Easing.in(Easing.cubic),
        useNativeDriver: true,
      }),
      RNAnimated.timing(backdropOpacity, {
        toValue: 0,
        duration: ANIM_DURATION,
        easing: Easing.in(Easing.cubic),
        useNativeDriver: true,
      }),
    ]).start(({ finished }) => {
      if (finished) onClose();
    });
  };

  const menuItems: MenuItem[] = [
    {
      id: 'vault',
      label: 'Media Vault',
      icon: 'lock',
      iconGradient: ['#60A5FA', '#2469BE'],
      onPress: () => {
        closeMenu();
        router.push('/(tabs)/vault');
